arguments.command:
cat << 'EOF' > /tmp/stackalloc_test/Program.cs
Span<nint> signedSpan = stackalloc nint[4];
for (int i = 0; i < signedSpan.Length; i++)
    signedSpan[i] = i * 10;

Span<nuint> unsignedSpan = stackalloc nuint[4];
for (int i = 0; i < unsignedSpan.Length; i++)
    unsignedSpan[i] = (nuint)(i * 20);

Console.WriteLine("Span<nint> (stackalloc):");
for (int i = 0; i < signedSpan.Length; i++)
    Console.WriteLine($"  [{i}] = {signedSpan[i]}");

Console.WriteLine("Span<nuint> (stackalloc):");
for (int i = 0; i < unsignedSpan.Length; i++)
    Console.WriteLine($"  [{i}] = {unsignedSpan[i]}");

Console.WriteLine($"nint size: {sizeof(nint)} bytes");
EOF
mkdir -p /tmp/stackalloc_test && cd /tmp/stackalloc_test && dotnet new console --force -o . --no-restore > /dev/null 2>&1 && cp Program.cs Program.cs.bak && cat Program.cs.bak > Program.cs && dotnet run --nologo 2>&1

